css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #070b0a; color: white; }
.layout { display: flex; min-height: 100vh; }
aside { width: 240px; background: #0d1710; border-right: 1px solid rgba(255,255,255,0.07); padding: 24px 14px; flex-shrink: 0; display: flex; flex-direction: column; }
.brand { font-size: 20px; font-weight: 800; padding: 0 10px; margin-bottom: 24px; color: #eab308; }
nav { display: flex; flex-direction: column; gap: 4px; margin-bottom: 24px; }
.nav-item { display: block; padding: 10px 14px; border-radius: 10px; color: #6b7280; font-size: 14px; cursor: pointer; transition: all 0.2s; } .nav-item:hover { background: rgba(255,255,255,0.05); } .nav-item.active { background: rgba(234,179,8,0.15); color: #eab308; font-weight: 600; }
.projects-list { border-top: 1px solid rgba(255,255,255,0.07); padding-top: 16px; }
.pl-header { font-size: 11px; font-weight: 700; color: #4b5563; letter-spacing: 2px; margin-bottom: 10px; padding: 0 10px; }
.pl-item { padding: 10px 14px; border-radius: 10px; font-size: 13px; color: #6b7280; cursor: pointer; transition: all 0.2s; margin-bottom: 2px; } .pl-item:hover { background: rgba(255,255,255,0.05); } .pl-item.active { background: rgba(234,179,8,0.1); color: #eab308; }
main { flex: 1; padding: 24px; overflow-y: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
.topbar h1 { font-size: 24px; font-weight: 800; } .topbar p { color: #6b7280; font-size: 13px; }
.tb-btn { padding: 10px 18px; border-radius: 12px; border: none; background: #eab308; color: #070b0a; font-weight: 800; font-size: 13px; cursor: pointer; }
.stats-row { display: grid; grid-template-columns: repeat(4,1fr); gap: 12px; margin-bottom: 24px; }
.stat-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 12px; padding: 14px 16px; display: flex; justify-content: space-between; align-items: center; } .stat-card span { font-size: 12px; color: #6b7280; } .stat-card strong { font-size: 22px; font-weight: 800; }
.kanban { display: grid; grid-template-columns: repeat(3,1fr); gap: 16px; }
.column { background: rgba(255,255,255,0.03); border-radius: 16px; padding: 16px; min-height: 400px; }
.col-header { display: flex; align-items: center; gap: 8px; margin-bottom: 14px; padding-bottom: 12px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.col-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; } .gray { background: #6b7280; } .yellow { background: #eab308; } .green { background: #22c55e; }
.col-header h3 { flex: 1; font-size: 14px; font-weight: 700; }
.col-count { width: 22px; height: 22px; border-radius: 50%; background: rgba(255,255,255,0.08); display: flex; align-items: center; justify-content: center; font-size: 11px; font-weight: 700; }
.col-tasks { display: flex; flex-direction: column; gap: 10px; min-height: 200px; }
.task-card { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.08); border-radius: 12px; padding: 14px; cursor: grab; transition: all 0.2s; user-select: none; } .task-card:hover { border-color: rgba(234,179,8,0.3); } .task-card.dragging { opacity: 0.5; }
.tc-title { font-size: 14px; font-weight: 600; margin-bottom: 8px; }
.tc-tags { display: flex; gap: 6px; margin-bottom: 8px; flex-wrap: wrap; }
.tc-tag { padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 700; }
.tc-footer { display: flex; justify-content: space-between; align-items: center; }
.tc-priority { width: 8px; height: 8px; border-radius: 50%; } .high { background: #ef4444; } .medium { background: #eab308; } .low { background: #22c55e; }
.tc-due { font-size: 11px; color: #6b7280; }

