let tasks = [
  {id:1,title:'Login sayfası tasarımı',status:'done',priority:'high',tags:['UI','Design'],due:'10 Oca',color:'#6366f1'},
  {id:2,title:'API endpoint entegrasyonu',status:'progress',priority:'high',tags:['Backend','API'],due:'15 Oca',color:'#3b82f6'},
  {id:3,title:'Dashboard grafikler',status:'progress',priority:'medium',tags:['Frontend'],due:'18 Oca',color:'#8b5cf6'},
  {id:4,title:'Unit test yazımı',status:'todo',priority:'medium',tags:['Testing'],due:'20 Oca',color:'#06b6d4'},
  {id:5,title:'Mobil uyumluluk',status:'todo',priority:'low',tags:['Mobile','CSS'],due:'25 Oca',color:'#22c55e'},
  {id:6,title:'Deployment yapılandırması',status:'todo',priority:'high',tags:['DevOps'],due:'28 Oca',color:'#f97316'}
];
let dragId = null;
const tagColors = {'UI':'rgba(99,102,241,0.2)|#818cf8','Design':'rgba(236,72,153,0.2)|#f9a8d4','Backend':'rgba(59,130,246,0.2)|#93c5fd','API':'rgba(6,182,212,0.2)|#67e8f9','Frontend':'rgba(139,92,246,0.2)|#c4b5fd','Testing':'rgba(34,197,94,0.2)|#86efac','Mobile':'rgba(249,115,22,0.2)|#fdba74','CSS':'rgba(20,184,166,0.2)|#5eead4','DevOps':'rgba(234,179,8,0.2)|#fde68a'};
function tagStyle(t) { const [bg,color] = (tagColors[t]||'rgba(255,255,255,0.1)|#9ca3af').split('|'); return `background:${bg};color:${color}`; }
function render() {
  ['todo','progress','done'].forEach(s => {
    const list = tasks.filter(t => t.status === s);
    document.getElementById('tasks-'+s).innerHTML = list.map(t => `
      <div class='task-card' draggable='true' id='task-${t.id}' ondragstart='dragStart(${t.id})'>
        <div class='tc-title'>${t.title}</div>
        <div class='tc-tags'>${t.tags.map(tag => `<span class='tc-tag' style='${tagStyle(tag)}'>${tag}</span>`).join('')}</div>
        <div class='tc-footer'><div style='display:flex;align-items:center;gap:6px'><div class='tc-priority ${t.priority}'></div><span style='font-size:11px;color:#6b7280;text-transform:capitalize'>${t.priority}</span></div><span class='tc-due'>${t.due}</span></div>
      </div>
    `).join('');
    document.getElementById('cnt-'+s).textContent = list.length;
  });
  document.getElementById('total-count').textContent = tasks.length;
  document.getElementById('done-count').textContent = tasks.filter(t=>t.status==='done').length;
  document.getElementById('progress-count').textContent = tasks.filter(t=>t.status==='progress').length;
  document.getElementById('todo-count').textContent = tasks.filter(t=>t.status==='todo').length;
}
function dragStart(id) { dragId = id; setTimeout(() => document.getElementById('task-'+id).classList.add('dragging'), 0); }
function dragOver(e) { e.preventDefault(); }
function drop(e, status) { e.preventDefault(); if (!dragId) return; const t = tasks.find(t=>t.id===dragId); if (t) t.status = status; dragId = null; render(); }
function addTask() {
  const title = prompt('Görev adı:');
  if (!title) return;
  tasks.push({id:Date.now(),title,status:'todo',priority:'medium',tags:['Yeni'],due:'TBD',color:'#eab308'});
  render();
}
render();
